import{_ as e,c as o,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Fase 1: Bootstrap - Estruturar Ideias de Produto | Tutorial do Agent App Factory","description":"Aprenda como a fase Bootstrap transforma ideias de produto vagas em um documento claro e estruturado input/idea.md. Este tutorial explica as responsabilidades do Bootstrap Agent, o uso da habilidade superpowers:brainstorm, a estrutura padrão do idea.md e a lista de verificação de qualidade.","frontmatter":{"title":"Fase 1: Bootstrap - Estruturar Ideias de Produto | Tutorial do Agent App Factory","sidebarTitle":"Estruturar Ideias de Produto","subtitle":"Fase 1: Bootstrap - Estruturar Ideias de Produto","description":"Aprenda como a fase Bootstrap transforma ideias de produto vagas em um documento claro e estruturado input/idea.md. Este tutorial explica as responsabilidades do Bootstrap Agent, o uso da habilidade superpowers:brainstorm, a estrutura padrão do idea.md e a lista de verificação de qualidade.","tags":["Pipeline","Bootstrap","Ideia de Produto"],"prerequisite":["start-pipeline-overview"],"order":80},"headers":[],"relativePath":"pt/hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md","filePath":"pt/hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md"}'),t={name:"pt/hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md"};function r(n,a,d,l,p,u){return s(),o("div",null,[...a[0]||(a[0]=[i(`<h1 id="fase-1-bootstrap-estruturar-ideias-de-produto" tabindex="-1">Fase 1: Bootstrap - Estruturar Ideias de Produto <a class="header-anchor" href="#fase-1-bootstrap-estruturar-ideias-de-produto" aria-label="Permalink to &quot;Fase 1: Bootstrap - Estruturar Ideias de Produto&quot;">​</a></h1><p>O Bootstrap é a primeira fase do pipeline do Agent App Factory, responsável por organizar sua ideia de produto vaga em um documento claro <code>input/idea.md</code>. Este é o ponto de partida para todas as fases subsequentes (PRD, UI, Tech, etc.), determinando a direção e qualidade de todo o projeto.</p><h2 id="o-que-voce-sera-capaz-de-fazer" tabindex="-1">O Que Você Será Capaz de Fazer <a class="header-anchor" href="#o-que-voce-sera-capaz-de-fazer" aria-label="Permalink to &quot;O Que Você Será Capaz de Fazer&quot;">​</a></h2><ul><li>Organizar ideias de produto vagas em um documento <code>input/idea.md</code> que siga o modelo padrão</li><li>Entender os limites de responsabilidade do Bootstrap Agent (apenas coleta informações, não cria requisitos)</li><li>Saber como usar a habilidade superpowers:brainstorm para explorar profundamente a ideia do produto</li><li>Ser capaz de julgar quais informações devem ser incluídas na fase Bootstrap e quais não devem</li></ul><h2 id="seu-problema-atual" tabindex="-1">Seu Problema Atual <a class="header-anchor" href="#seu-problema-atual" aria-label="Permalink to &quot;Seu Problema Atual&quot;">​</a></h2><p>Você pode ter uma ideia de produto, mas a descrição é vaga:</p><ul><li>&quot;Quero fazer um aplicativo de fitness&quot; (muito geral)</li><li>&quot;Fazer um aplicativo como o Xiaohongshu&quot; (não especifica diferenciação)</li><li>&quot;Os usuários precisam de uma ferramenta melhor de gerenciamento de tarefas&quot; (não especifica o problema específico)</li></ul><p>Essas descrições vagas levarão a fases subsequentes (PRD, UI, Tech) sem entradas claras, e o aplicativo final pode desviar completamente das suas expectativas.</p><h2 id="quando-usar-esta-tecnica" tabindex="-1">Quando Usar Esta Técnica <a class="header-anchor" href="#quando-usar-esta-tecnica" aria-label="Permalink to &quot;Quando Usar Esta Técnica&quot;">​</a></h2><p>Quando você estiver pronto para iniciar o pipeline e atender às seguintes condições:</p><ol><li><strong>Ter uma ideia inicial do produto</strong> (mesmo que seja apenas uma frase)</li><li><strong>Ainda não começou a escrever o documento de requisitos</strong> (PRD está em fases posteriores)</li><li><strong>Ainda não decidiu a stack tecnológica ou o estilo de UI</strong> (essas são fases posteriores)</li><li><strong>Deseja controlar o escopo do produto e evitar over-design</strong> (a fase Bootstrap definirá explicitamente os não objetivos)</li></ol><h2 id="🎒-preparacao-antes-de-comecar" tabindex="-1">🎒 Preparação Antes de Começar <a class="header-anchor" href="#🎒-preparacao-antes-de-comecar" aria-label="Permalink to &quot;🎒 Preparação Antes de Começar&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Pré-requisitos</p><p>Antes de começar a fase Bootstrap, certifique-se de:</p><ul><li>✅ Completou <a href="./../../start/init-project/">Inicialização do Projeto</a></li><li>✅ Entendeu <a href="./../../start/pipeline-overview/">Visão Geral do Pipeline de 7 Fases</a></li><li>✅ Instalou e configurou o assistente de AI (recomenda-se Claude Code)</li><li>✅ Preparou sua ideia de produto (mesmo que seja vaga)</li></ul></div><h2 id="ideia-central" tabindex="-1">Ideia Central <a class="header-anchor" href="#ideia-central" aria-label="Permalink to &quot;Ideia Central&quot;">​</a></h2><h3 id="o-que-e-a-fase-bootstrap" tabindex="-1">O que é a Fase Bootstrap? <a class="header-anchor" href="#o-que-e-a-fase-bootstrap" aria-label="Permalink to &quot;O que é a Fase Bootstrap?&quot;">​</a></h3><p>O <strong>Bootstrap</strong> é o ponto de partida de todo o pipeline. Sua única responsabilidade é <strong>organizar ideias de produto fragmentadas em um documento estruturado</strong>.</p><div class="info custom-block"><p class="custom-block-title">Não é um Gerente de Produto</p><p>O Bootstrap Agent não é um gerente de produto; ele não criará requisitos ou projetará recursos por você. Suas tarefas são:</p><ul><li>Coletar informações que você já forneceu</li><li>Organizar e estruturar essas informações</li><li>Apresentar de acordo com o modelo padrão</li></ul><p>Ele não decidirá &quot;quais recursos deve ter&quot;, apenas ajudará você a expressar claramente &quot;o que você quer&quot;.</p></div><h3 id="por-que-estruturar" tabindex="-1">Por Que Estruturar? <a class="header-anchor" href="#por-que-estruturar" aria-label="Permalink to &quot;Por Que Estruturar?&quot;">​</a></h3><p>Imagine que você diz ao cozinheiro: &quot;Quero comer algo gostoso&quot;</p><ul><li>❌ Descrição vaga: O cozinheiro só pode adivinhar, talvez fazendo um prato que você não quer comer nada</li><li>✅ Descrição estruturada: &quot;Quero um prato de Sichuan picante, sem coentro, que combine bem com arroz&quot;</li></ul><p>A fase Bootstrap é transformar &quot;quero comer algo gostoso&quot; em &quot;um prato de Sichuan picante, sem coentro&quot;.</p><h3 id="estrutura-do-documento-de-saida" tabindex="-1">Estrutura do Documento de Saída <a class="header-anchor" href="#estrutura-do-documento-de-saida" aria-label="Permalink to &quot;Estrutura do Documento de Saída&quot;">​</a></h3><p>A fase Bootstrap gerará <code>input/idea.md</code>, contendo os seguintes capítulos:</p><table tabindex="0"><thead><tr><th>Capítulo</th><th>Conteúdo</th><th>Exemplo</th></tr></thead><tbody><tr><td><strong>Descrição Breve</strong></td><td>1-2 frases resumindo o produto</td><td>&quot;Um aplicativo de contabilidade móvel para ajudar jovens a registrar rapidamente despesas diárias&quot;</td></tr><tr><td><strong>Problema (Problem)</strong></td><td>A principal dor do usuário</td><td>&quot;Jovens descobrem que ultrapassaram o orçamento no final do mês, mas não sabem onde o dinheiro foi&quot;</td></tr><tr><td><strong>Usuário Alvo (Target User)</strong></td><td>Perfil específico do público</td><td>&quot;Jovens de 18-30 anos recém-entrados no mercado de trabalho, com habilidades técnicas médias&quot;</td></tr><tr><td><strong>Valor Central (Core Value)</strong></td><td>Por que é valioso</td><td>&quot;Registro em 3 segundos, economizando 80% do tempo em comparação com verificação manual&quot;</td></tr><tr><td><strong>Suposições (Assumptions)</strong></td><td>2-4 suposições verificáveis</td><td>&quot;Usuários estão dispostos a gastar 2 minutos aprendendo o aplicativo, se puderem controlar o orçamento&quot;</td></tr><tr><td><strong>Não Objetivos (Non‑Goals)</strong></td><td>Explicitar o que não fazer</td><td>&quot;Não planejamento de orçamento ou conselhos financeiros&quot;</td></tr></tbody></table><h2 id="siga-minhas-instrucoes" tabindex="-1">Siga Minhas Instruções <a class="header-anchor" href="#siga-minhas-instrucoes" aria-label="Permalink to &quot;Siga Minhas Instruções&quot;">​</a></h2><h3 id="passo-1-prepare-sua-ideia-de-produto" tabindex="-1">Passo 1: Prepare Sua Ideia de Produto <a class="header-anchor" href="#passo-1-prepare-sua-ideia-de-produto" aria-label="Permalink to &quot;Passo 1: Prepare Sua Ideia de Produto&quot;">​</a></h3><p>Antes de iniciar o pipeline, pense claramente sobre sua ideia de produto. Pode ser uma descrição completa ou apenas uma ideia simples.</p><p><strong>Exemplo</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Quero fazer um aplicativo de fitness para ajudar iniciantes de fitness a registrar treinamentos, incluindo tipo de exercício, duração, calorias, e também ver estatísticas da semana.</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">A ideia pode ser bruta</p><p>Mesmo que seja apenas uma frase, não há problema. O Bootstrap Agent usará a habilidade superpowers:brainstorm para ajudá-lo a completar as informações.</p></div><h3 id="passo-2-inicie-o-pipeline-ate-a-fase-bootstrap" tabindex="-1">Passo 2: Inicie o Pipeline até a Fase Bootstrap <a class="header-anchor" href="#passo-2-inicie-o-pipeline-ate-a-fase-bootstrap" aria-label="Permalink to &quot;Passo 2: Inicie o Pipeline até a Fase Bootstrap&quot;">​</a></h3><p>No diretório do projeto Factory, execute:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Inicie o pipeline (ainda não iniciado)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Ou especifique diretamente para começar do bootstrap</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bootstrap</span></span></code></pre></div><p>A CLI mostrará o status atual e as fases disponíveis.</p><h3 id="passo-3-o-assistente-de-ai-le-a-definicao-do-bootstrap-agent" tabindex="-1">Passo 3: O Assistente de AI Lê a Definição do Bootstrap Agent <a class="header-anchor" href="#passo-3-o-assistente-de-ai-le-a-definicao-do-bootstrap-agent" aria-label="Permalink to &quot;Passo 3: O Assistente de AI Lê a Definição do Bootstrap Agent&quot;">​</a></h3><p>O assistente de AI (como Claude Code) lerá automaticamente <code>agents/bootstrap.agent.md</code>, entendendo suas responsabilidades e restrições.</p><div class="info custom-block"><p class="custom-block-title">Responsabilidades do Agent</p><p>O Bootstrap Agent só pode:</p><ul><li>Ler a ideia de produto fornecida pelo usuário na conversa</li><li>Escrever em <code>input/idea.md</code></li></ul><p>Ele não pode:</p><ul><li>Ler outros arquivos</li><li>Escrever em outros diretórios</li><li>Criar novos requisitos</li></ul></div><h3 id="passo-4-uso-obrigatorio-da-habilidade-superpowers-brainstorm" tabindex="-1">Passo 4: Uso Obrigatório da Habilidade superpowers:brainstorm <a class="header-anchor" href="#passo-4-uso-obrigatorio-da-habilidade-superpowers-brainstorm" aria-label="Permalink to &quot;Passo 4: Uso Obrigatório da Habilidade superpowers:brainstorm&quot;">​</a></h3><p>Este é um passo crítico da fase Bootstrap. O assistente de AI <strong>deve</strong> primeiro chamar a habilidade <code>superpowers:brainstorm</code>, mesmo que você ache que as informações já estão completas.</p><p><strong>Função da habilidade brainstorm</strong>:</p><ol><li><strong>Explorar profundamente a essência do problema</strong>: Descubra pontos cegos em sua descrição através de perguntas estruturadas</li><li><strong>Definir o perfil do usuário alvo</strong>: Ajude você a esclarecer &quot;quem exatamente vender&quot;</li><li><strong>Validar o valor central</strong>: Encontre diferenciação comparando com concorrentes</li><li><strong>Identificar suposições implícitas</strong>: Liste suposições que você assume mas não verificou</li><li><strong>Controlar o escopo do produto</strong>: Defina limites através de não objetivos</li></ol><p><strong>O que o assistente de AI fará</strong>:</p><ul><li>Chamar a habilidade <code>superpowers:brainstorm</code></li><li>Fornecer sua ideia original</li><li>Fazer perguntas a você através das questões geradas pela habilidade</li><li>Coletar suas respostas e refinar a ideia</li></ul><div class="danger custom-block"><p class="custom-block-title">Pular este passo resultará em rejeição</p><p>O scheduler Sisyphus verificará se a habilidade brainstorm foi usada. Se não, o produto gerado pelo Bootstrap Agent será rejeitado e precisará ser reexecutado.</p></div><h3 id="passo-5-confirme-o-conteudo-do-idea-md" tabindex="-1">Passo 5: Confirme o Conteúdo do idea.md <a class="header-anchor" href="#passo-5-confirme-o-conteudo-do-idea-md" aria-label="Permalink to &quot;Passo 5: Confirme o Conteúdo do idea.md&quot;">​</a></h3><p>Depois que o Bootstrap Agent terminar, ele gerará <code>input/idea.md</code>. Você precisa verificar cuidadosamente:</p><p><strong>Pontos de Verificação ✅</strong>:</p><ol><li><p><strong>A descrição breve está clara?</strong></p><ul><li>✅ Inclui: o que fazer + para quem + qual problema resolver</li><li>❌ Muito geral: &quot;Uma ferramenta para melhorar a eficiência&quot;</li></ul></li><li><p><strong>A descrição do problema é específica?</strong></p><ul><li>✅ Inclui: cenário + dificuldade + resultado negativo</li><li>❌ Vago: &quot;A experiência do usuário não é boa&quot;</li></ul></li><li><p><strong>O usuário alvo está claro?</strong></p><ul><li>✅ Tem perfil específico (idade/ocupação/habilidades técnicas)</li><li>❌ Vago: &quot;Todos&quot;</li></ul></li><li><p><strong>O valor central é quantificável?</strong></p><ul><li>✅ Tem benefício específico (economiza 80% do tempo)</li><li>❌ Vago: &quot;Melhorar a eficiência&quot;</li></ul></li><li><p><strong>As suposições são verificáveis?</strong></p><ul><li>✅ Podem ser verificadas por pesquisa de usuários</li><li>❌ Julgamento subjetivo: &quot;Os usuários gostarão&quot;</li></ul></li><li><p><strong>Os não objetivos são suficientes?</strong></p><ul><li>✅ Listar pelo menos 3 recursos que não farão</li><li>❌ Faltam ou muito poucos</li></ul></li></ol><h3 id="passo-6-escolha-continuar-retentar-ou-pausar" tabindex="-1">Passo 6: Escolha Continuar, Retentar ou Pausar <a class="header-anchor" href="#passo-6-escolha-continuar-retentar-ou-pausar" aria-label="Permalink to &quot;Passo 6: Escolha Continuar, Retentar ou Pausar&quot;">​</a></h3><p>Depois de confirmar que está correto, a CLI mostrará opções:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Escolha</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uma</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ação:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[1] Continuar (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">entrar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> na</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fase</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PRD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[2] Retentar (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">regenerar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> idea.md</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[3] Pausar (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">continuar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> depois</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Recomendado verificar no editor de código primeiro</p><p>Antes de confirmar no assistente de AI, abra <code>input/idea.md</code> no editor de código e verifique palavra por palavra. Uma vez entrando na fase PRD, o custo de modificação será maior.</p></div><h2 id="alertas-de-erros-comuns" tabindex="-1">Alertas de Erros Comuns <a class="header-anchor" href="#alertas-de-erros-comuns" aria-label="Permalink to &quot;Alertas de Erros Comuns&quot;">​</a></h2><h3 id="erro-1-descricao-da-ideia-muito-vaga" tabindex="-1">Erro 1: Descrição da ideia muito vaga <a class="header-anchor" href="#erro-1-descricao-da-ideia-muito-vaga" aria-label="Permalink to &quot;Erro 1: Descrição da ideia muito vaga&quot;">​</a></h3><p><strong>Exemplo Errado</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Quero fazer um aplicativo de fitness</span></span></code></pre></div><p><strong>Consequência</strong>: O Bootstrap Agent fará muitas perguntas através da habilidade brainstorm para completar as informações.</p><p><strong>Recomendação</strong>: Descreva claramente desde o início:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Quero fazer um aplicativo de fitness móvel para ajudar iniciantes de fitness a registrar treinamentos, incluindo tipo de exercício, duração, calorias, e também ver estatísticas da semana.</span></span></code></pre></div><h3 id="erro-2-incluir-detalhes-de-implementacao-tecnica" tabindex="-1">Erro 2: Incluir detalhes de implementação técnica <a class="header-anchor" href="#erro-2-incluir-detalhes-de-implementacao-tecnica" aria-label="Permalink to &quot;Erro 2: Incluir detalhes de implementação técnica&quot;">​</a></h3><p><strong>Exemplo Errado</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Espero usar React Native para construir, backend com Express, banco de dados é Prisma...</span></span></code></pre></div><p><strong>Consequência</strong>: O Bootstrap Agent rejeitará esses conteúdos (ele só coleta ideias de produto, a stack tecnológica é decidida na fase Tech).</p><p><strong>Recomendação</strong>: Diga apenas &quot;o que fazer&quot;, não &quot;como fazer&quot;.</p><h3 id="erro-3-descricao-do-usuario-alvo-muito-vaga" tabindex="-1">Erro 3: Descrição do usuário alvo muito vaga <a class="header-anchor" href="#erro-3-descricao-do-usuario-alvo-muito-vaga" aria-label="Permalink to &quot;Erro 3: Descrição do usuário alvo muito vaga&quot;">​</a></h3><p><strong>Exemplo Errado</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Todos que precisam de fitness</span></span></code></pre></div><p><strong>Consequência</strong>: Fases subsequentes não podem definir claramente a direção de design.</p><p><strong>Recomendação</strong>: Defina o perfil:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Iniciantes de fitness de 18-30 anos, começando a treinar sistematicamente, habilidades técnicas médias, esperam registro simples e visualização de estatísticas.</span></span></code></pre></div><h3 id="erro-4-falta-ou-poucos-nao-objetivos" tabindex="-1">Erro 4: Falta ou poucos não objetivos <a class="header-anchor" href="#erro-4-falta-ou-poucos-nao-objetivos" aria-label="Permalink to &quot;Erro 4: Falta ou poucos não objetivos&quot;">​</a></h3><p><strong>Exemplo Errado</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Não objetivos: Nenhum</span></span></code></pre></div><p><strong>Consequência</strong>: As fases subsequentes PRD e Code podem ter over-design, aumentando a complexidade técnica.</p><p><strong>Recomendação</strong>: Liste pelo menos 3 itens:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Não objetivos:</span></span>
<span class="line"><span>- Colaboração em equipe e recursos sociais (MVP focado no individual)</span></span>
<span class="line"><span>- Análise de dados complexos e relatórios</span></span>
<span class="line"><span>- Integração com dispositivos de fitness de terceiros</span></span></code></pre></div><h3 id="erro-5-suposicoes-nao-verificaveis" tabindex="-1">Erro 5: Suposições não verificáveis <a class="header-anchor" href="#erro-5-suposicoes-nao-verificaveis" aria-label="Permalink to &quot;Erro 5: Suposições não verificáveis&quot;">​</a></h3><p><strong>Exemplo Errado</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Suposição: Os usuários gostarão do nosso design</span></span></code></pre></div><p><strong>Consequência</strong>: Não pode ser verificada por pesquisa de usuários, o MVP pode falhar.</p><p><strong>Recomendação</strong>: Escreva suposições verificáveis:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Suposição: Os usuários estão dispostos a gastar 5 minutos aprendendo o aplicativo, se puderem ajudar a registrar treinamentos sistematicamente.</span></span></code></pre></div><h2 id="resumo-da-licao" tabindex="-1">Resumo da Lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da Lição&quot;">​</a></h2><p>O núcleo da fase Bootstrap é <strong>estruturação</strong>:</p><ol><li><strong>Entrada</strong>: Sua ideia de produto vaga</li><li><strong>Processo</strong>: O assistente de AI explora profundamente através da habilidade superpowers:brainstorm</li><li><strong>Saída</strong>: <code>input/idea.md</code> que segue o modelo padrão</li><li><strong>Validação</strong>: Verificar se a descrição é específica, se o usuário está claro, se o valor é quantificável</li></ol><div class="tip custom-block"><p class="custom-block-title">Princípios Chave</p><ul><li>❌ O que não fazer: não criar requisitos, não projetar recursos, não decidir a stack tecnológica</li><li>✅ O que fazer apenas: coletar informações, organizar estruturar, apresentar por modelo</li></ul></div><h2 id="proximo-passo" tabindex="-1">Próximo Passo <a class="header-anchor" href="#proximo-passo" aria-label="Permalink to &quot;Próximo Passo&quot;">​</a></h2><blockquote><p>Na próxima lição, aprenderemos <strong><a href="./../stage-prd/">Fase 2: PRD - Gerar Documento de Requisitos de Produto</a></strong>.</p><p>Você aprenderá:</p><ul><li>Como transformar idea.md em PRD nível MVP</li><li>O que inclui PRD (histórias de usuários, lista de recursos, requisitos não funcionais)</li><li>Como definir o escopo e prioridade do MVP</li><li>Por que o PRD não pode incluir detalhes técnicos</li></ul></blockquote><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do Código Fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do Código Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir para ver localização do código fonte</strong></summary><blockquote><p>Última atualização: 2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do Arquivo</th><th>Linhas</th></tr></thead><tbody><tr><td>Definição do Bootstrap Agent</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/bootstrap.agent.md" target="_blank" rel="noreferrer"><code>agents/bootstrap.agent.md</code></a></td><td>1-93</td></tr><tr><td>Bootstrap Skill</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/skills/bootstrap/skill.md" target="_blank" rel="noreferrer"><code>skills/bootstrap/skill.md</code></a></td><td>1-433</td></tr><tr><td>Definição do Pipeline (Fase Bootstrap)</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/pipeline.yaml" target="_blank" rel="noreferrer"><code>pipeline.yaml</code></a></td><td>8-18</td></tr><tr><td>Definição do Scheduler</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>1-100+</td></tr></tbody></table><p><strong>Restrições Chave</strong>:</p><ul><li><strong>Uso obrigatório da habilidade brainstorm</strong>: bootstrap.agent.md:70-71</li><li><strong>Proibição de detalhes técnicos</strong>: bootstrap.agent.md:47</li><li><strong>Proibição de mesclar múltiplas ideias</strong>: bootstrap.agent.md:48</li><li><strong>O arquivo de saída deve ser salvo em input/idea.md</strong>: bootstrap.agent.md:50</li></ul><p><strong>Condições de Saída</strong> (pipeline.yaml:15-18):</p><ul><li>idea.md existe</li><li>idea.md descreve uma ideia de produto coerente</li><li>O Agent usou a habilidade <code>superpowers:brainstorm</code> para exploração profunda</li></ul><p><strong>Framework do Conteúdo da Skill</strong>:</p><ul><li><strong>Framework de Pensamento</strong>: extrair vs criar, problema primeiro, concretização, verificação de suposições</li><li><strong>Modelo de Perguntas</strong>: sobre problema, usuário alvo, valor central, suposições MVP, não objetivos</li><li><strong>Técnicas de Extração de Informações</strong>: de recursos para problema, de reclamações para requisitos, identificar suposições implícitas</li><li><strong>Lista de Verificação de Qualidade</strong>: integridade, especificidade, consistência, itens proibidos</li><li><strong>Princípios de Decisão</strong>: perguntar primeiro, orientado a problema, específico优于 abstrato, verificabilidade, controle de escopo</li><li><strong>Tratamento de Cenários Comuns</strong>: usuário fornece apenas uma frase, descreve muitos recursos, descreve concorrentes, ideia contraditória</li><li><strong>Comparação de Exemplos</strong>: idea.md ruim vs idea.md bom</li></ul></details>`,91)])])}const h=e(t,[["render",r]]);export{m as __pageData,h as default};
